fragment:


		@("Calling tokeninfo for user roles...")


		https://auth-i.bmwgroup.net/auth/oauth2/realms/root/realms/machine2machine/tokeninfo
		GET

			@((string)context.Variables["userAuthHeader"])





				@($"tokeninfo failed: status={((IResponse)context.Variables["tokeninfo"]).StatusCode}")




					Bearer error="invalid_token"

				{"error":"Invalid token"}



	<set-variable name="tokeninfoJson" value="@(((IResponse)context.Variables["tokeninfo"]).Body.As(true))" />



				@($"tokeninfo error: {((JObject)context.Variables["tokeninfoJson"])["error"]}")




					Bearer error="invalid_token"

				{"error":"Invalid token"}



	<set-variable name="hasRequiredRole" value="@{
        var obj = (JObject)context.Variables["tokeninfoJson"];
        var rolesToken = obj.SelectToken("b2xroles");
        System.Collections.Generic.IEnumerable roles = System.Linq.Enumerable.Empty();

        if (rolesToken != null)
        {
            if (rolesToken.Type == JTokenType.Array)
            {
                roles = rolesToken.Values().Select(r => (r ?? "").Trim());
            }
            else
            {
                roles = ((string)rolesToken ?? "")
                        .Split(new[]{',' ,' '}, StringSplitOptions.RemoveEmptyEntries)
                        .Select(r => r.Trim());
            }
        }

        var required = new [] { "IVSR_Core","IVSR_Dealer","IVSR_CE_DispositionClerk","IVSR_New_Menu","IVSR_Admin_VG","s_gate_cn_user" };
        return roles.Intersect(required, StringComparer.OrdinalIgnoreCase).Any();
      }" />

		@($"hasRequiredRole = {(bool)context.Variables["hasRequiredRole"]}")






					application/json

				{"error":"insufficient_role","required_any_of":["IVSR_Core","IVSR_Dealer","IVSR_CE_DispositionClerk","IVSR_New_Menu","IVSR_Admin_VG"]}
